    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 58,
            .@"string_sq" => 64,
            .@"string_dq" => 65,
            .@"indent" => 70,
            .@"outdent" => 71,
            .@"integer" => 94,
            .@"bar_capture" => 102,
            .@"ternary_if" => 112,
            .@"post_if" => 116,
            .@"minus_prefix" => 127,
            .@"real" => 135,
            .@"true" => 136,
            .@"false" => 137,
            .@"dot_lbrace" => 142,
            .@"colon" => 59,
            .@"assign" => 76,
            .@"comma" => 84,
            .@"not_sym" => 88,
            .@"question" => 89,
            .@"star" => 90,
            .@"lbracket" => 92,
            .@"rbracket" => 93,
            .@"lparen" => 96,
            .@"rparen" => 99,
            .@"dot" => 109,
            .@"ampersand" => 129,
            .@"tilde" => 130,
            .@"at" => 141,
            .@"rbrace" => 145,
            .@"lbrace" => 146,
            .@"bar" => 168,
            .@"caret" => 169,
            .@"lt" => 172,
            .@"gt" => 173,
            .@"plus" => 178,
            .@"minus" => 179,
            .@"slash" => 180,
            .@"percent" => 181,
            .@"arrow" => 87,
            .@"dotdot" => 110,
            .@"fat_arrow" => 111,
            .@"nullish" => 113,
            .@"plus_assign" => 122,
            .@"minus_assign" => 123,
            .@"star_assign" => 124,
            .@"slash_assign" => 125,
            .@"const_assign" => 126,
            .@"pipe" => 165,
            .@"or_sym" => 166,
            .@"and_sym" => 167,
            .@"eq" => 170,
            .@"ne" => 171,
            .@"le" => 174,
            .@"ge" => 175,
            .@"lshift" => 176,
            .@"rshift" => 177,
            .@"power" => 182,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return symIdent;
        if (self.tryIdentAsKeyword(token, text)) |sym| return sym;
        return symIdent;
    }

    fn tryIdentAsKeyword(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.stateStack.getLast();
        if (zag.keywordAs(text)) |id| {
            const idIdx = @intFromEnum(id);
            const sym = keywordToSymbol[idIdx];
            if (sym != 0 and getAction(state, sym) > 0) {
                self.lastMatchedId = @intCast(idIdx);
                return sym;
            }
            const fallback = keywordFallbackSymbol;
            if (fallback != 0 and getAction(state, fallback) > 0) {
                self.lastMatchedId = @intCast(idIdx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *Parser) !Sexp {
        self.injectedToken = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *Parser) !Sexp {
        self.injectedToken = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

